// 1. Configuration InfluxDB via Grafana Proxy
// ⚠️ IMPORTANT : Remplace ces valeurs par ton bon UID et ta bonne DB InfluxDB
const INFLUX_UID = "cfhadglk24agwe"; // ex: bffi1k5l0fls0e
const INFLUX_DB = "Serre-puit";

// 2. Génération des abscisses (00:00, 00:30...)
const times = [];
for (let i = 0; i < 24; i++) {
  let h = i.toString().padStart(2, '0');
  times.push(`${h}:00`);
  times.push(`${h}:30`);
}

// 3. Initialisation de base
if (!window.consigneVentilateur) {
  window.consigneVentilateur = new Array(48).fill(50);
  window.hasFetchedConsignes = false; // Permet de ne lire InfluxDB qu'au premier chargement
}

// 4. LECTURE DE L'HISTORIQUE DEPUIS INFLUXDB
if (!window.hasFetchedConsignes && context.panel && context.panel.data && context.panel.data.state === 'Done') {

  let hasLoadedData = false;

  times.forEach((t, i) => {
    let fieldName = "v_" + t.replace(':', '_'); // ex: v_18_00
    let foundValue = null;

    for (let series of context.panel.data.series) {

      // 1. On regarde si le nom de la série correspond (ex: "consignes_ventilateur.last_v_18_00" finit bien par "v_18_00")
      if (series.name && series.name.endsWith(fieldName)) {

        // 2. Si c'est la bonne série, on prend la colonne contenant les nombres (nommée "Value" dans Grafana)
        let field = series.fields.find(f => f.type === 'number');

        if (field && field.values && field.values.length > 0) {
          // 3. On récupère la dernière valeur non nulle
          for (let j = field.values.length - 1; j >= 0; j--) {
            let val = field.values.get ? field.values.get(j) : field.values[j];

            if (val !== null && val !== undefined && !isNaN(val)) {
              foundValue = val;
              break;
            }
          }
        }
      }

      if (foundValue !== null) break; // Valeur trouvée pour cette heure, on passe à la suivante
    }

    if (foundValue !== null) {
      window.consigneVentilateur[i] = foundValue;
      hasLoadedData = true;
    }
  });

  if (hasLoadedData) {
    window.hasFetchedConsignes = true;
    console.log("✅ Valeurs InfluxDB récupérées avec succès :", window.consigneVentilateur);

    // On met à jour le graphique
    if (typeof context !== 'undefined' && context.echartsInstance) {
      context.echartsInstance.setOption({ series: [{ data: window.consigneVentilateur }] });
    }
  } else {
    console.warn("⚠️ Impossible de lire les valeurs. On garde les 50 par défaut.");
  }
}

// 5. Interactivité et dessin à la souris
setTimeout(() => {
  let chart = null;

  if (typeof context !== 'undefined') chart = context.echartsInstance || (context.panel && context.panel.chart);
  if (!chart && typeof echartsInstance !== 'undefined') chart = echartsInstance;

  if (chart) {
    chart.getZr().off('mousedown');
    chart.getZr().off('mousemove');
    chart.getZr().off('click');

    const updatePoint = (params) => {
      const pointInPixel = [params.offsetX, params.offsetY];

      if (chart.containPixel('grid', pointInPixel)) {
        const pointInGrid = chart.convertFromPixel({ seriesIndex: 0 }, pointInPixel);
        let xIndex = Math.round(pointInGrid[0]);
        let yRawValue = pointInGrid[1];

        // Arrondi 5% et blocage entre 30% et 100%
        let yValue = Math.round(yRawValue / 5) * 5;
        if (yValue > 100) yValue = 100;
        if (yValue < 30) yValue = 30;

        if (window.consigneVentilateur[xIndex] !== yValue) {
          window.consigneVentilateur[xIndex] = yValue;
          chart.setOption({ series: [{ data: window.consigneVentilateur }] });
        }
        chart.dispatchAction({ type: 'showTip', seriesIndex: 0, dataIndex: xIndex });
      }
    };

    chart.getZr().on('mousedown', function (params) { updatePoint(params); });
    chart.getZr().on('mousemove', function (params) {
      if (params.event && params.event.buttons === 1) { updatePoint(params); }
    });
  }
}, 100);

// 6. Rendu du graphique et bouton d'envoi
return {
  tooltip: {
    show: true,
    trigger: 'axis',
    axisPointer: { type: 'line', lineStyle: { color: '#ff9900', width: 2, type: 'dashed' } },
    formatter: function (params) {
      return `🕒 <b>${params[0].name}</b><br/>💨 Consigne : <b style="color:#ff9900;">${params[0].value}%</b>`;
    }
  },

  toolbox: {
    feature: {
      mySendAction: {
        show: true,
        title: 'Envoyer vers InfluxDB',
        icon: 'path://M2.01 21L23 12 2.01 3 2 10l15 2-15 2z',
        onclick: function () {
          let sTemp = 25;
          let sVit = 100;

          try {
            if (typeof context !== 'undefined' && context.grafana) {
              let rawTemp = context.grafana.replaceVariables('${Temperature_Seuil}');
              let rawVit = context.grafana.replaceVariables('${Vitesse_Seuil}');

              let pTemp = parseFloat(rawTemp);
              let pVit = parseFloat(rawVit);

              if (!isNaN(pTemp) && !rawTemp.includes('seuil_temp')) sTemp = pTemp;
              if (!isNaN(pVit) && !rawVit.includes('seuil_vitesse')) sVit = pVit;
            }
          } catch (e) {
            console.error("❌ Erreur lecture Grafana :", e);
          }

          // Construction de la ligne pour InfluxDB (Line Protocol)
          let fields = `seuil_temp=${sTemp},seuil_vitesse=${sVit}`;

          times.forEach((t, i) => {
            let fieldName = "v_" + t.replace(':', '_');
            fields += `,${fieldName}=${window.consigneVentilateur[i]}`;
          });

          const ligne = `consignes_ventilateur ${fields}`;
          const url = `/api/datasources/proxy/uid/${INFLUX_UID}/api/v3/write_lp?db=${INFLUX_DB}&precision=second`;

          fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'text/plain' },
            body: ligne
          })
            .then(response => {
              if (response.ok) {
                if (typeof context !== 'undefined' && context.grafana) {
                  context.grafana.notifySuccess(['Succès', 'Tracé enregistré dans InfluxDB !']);
                } else {
                  alert("✅ Consignes expédiées avec succès !");
                }
              } else {
                if (typeof context !== 'undefined' && context.grafana) {
                  context.grafana.notifyError(['Erreur', 'Code InfluxDB : ' + response.status]);
                } else {
                  alert(`❌ Erreur InfluxDB : ${response.status}`);
                }
              }
            })
            .catch(err => {
              if (typeof context !== 'undefined' && context.grafana) {
                context.grafana.notifyError(['Erreur réseau', 'Impossible de joindre la base']);
              } else {
                alert(`❌ Impossible de joindre InfluxDB.\nErreur: ${err}`);
              }
            });
        }
      }
    }
  },

  grid: { left: '5%', right: '5%', bottom: '10%', top: '15%', containLabel: true },
  xAxis: { type: 'category', data: times },
  yAxis: { type: 'value', min: 30, max: 100, name: 'Vitesse (%)' },
  series: [
    {
      data: window.consigneVentilateur,
      type: 'line',
      step: 'middle',
      symbolSize: 8,
      lineStyle: { width: 3, color: '#ff9900' },
      itemStyle: { color: '#ff9900' },
      areaStyle: { color: 'rgba(255, 153, 0, 0.2)' }
    }
  ]
};
